import utils.NetworkUtils;

import java.net.SocketException;
import java.security.NoSuchAlgorithmException;

import static utils.NetworkUtils.*;

public class Hardware {

    public static void main(String[] args) throws NoSuchAlgorithmException, SocketException {
        byte[] hashed = hashString("This is a hashed String", "SHA-256");
        System.out.println("String hash: " + SHA256ToHex(hashed) + " in bytes: " + hashed);

        byte[] macHash = getMacAddress();
        System.out.println("MAC address: " + macBytesToHex(macHash) + " in bytes: " + macHash);
        // Example of data that would be hashed and sent
        byte[] completePacketHash = hashString("<?xml version=\"1.0\"?>\n" +
                "<DATA>\n" +
                "    <HASH></HASH>\n" +
                "    <USERNAME>John Sneed</USERNAME>\n" +
                "    <MAC_ADDRESS>C4-3D-1A-3E-E3-51</MAC_ADDRESS>\n" +
                "    <DEVICE_NAME>grimoire</DEVICE_NAME>\n" +
                "    <ROOT1></ROOT1>\n" +
                "    <ROOT2></ROOT2>\n" +
                "    <MESSAGE>SAVE THE CHICKENS, OPALINE BLOOD DIAMOND INCOMING!!!!</MESSAGE>\n" +
                "</DATA>", "SHA-256");
        System.out.println("Hash of a message: " + SHA256ToHex(completePacketHash) + " in bytes: " + completePacketHash);
    }
}
